 36→@AndroidEntryPoint
 37→class SiteCreationDomainsFragment : SiteCreationBaseFormFragment() {
 38→    private var searchInputWithHeader: SearchInputWithHeader? = null
 39→    private val viewModel: SiteCreationDomainsViewModel by activityViewModels()
 40→
 41→    @Inject
 42→    internal lateinit var uiHelpers: UiHelpers
 43→
 44→    @Inject
 45→    internal lateinit var displayUtils: DisplayUtilsWrapper
 46→
 47→    private var binding: SiteCreationDomainsScreenBinding? = null
 48→
 49→    override fun onAttach(context: Context) {
 50→        super.onAttach(context)
 51→        check(context is DomainsScreenListener) { "Parent activity must implement DomainsScreenListener." }
 52→        check(context is OnHelpClickedListener) { "Parent activity must implement OnHelpClickedListener." }
 53→    }
 54→
 55→    override fun getContentLayout() = R.layout.site_creation_domains_screen
 56→
 57→    override val screenTitle get() = requireArguments().getString(EXTRA_SCREEN_TITLE).orEmpty()
 58→
 59→    override fun setBindingViewStubListener(parentBinding: SiteCreationFormScreenBinding) {
 60→        parentBinding.siteCreationFormContentStub.setOnInflateListener { _, inflated ->
 61→            binding = SiteCreationDomainsScreenBinding.bind(inflated)
 62→        }
 63→    }
 64→
 65→    override fun setupContent() {
 66→        binding?.let {
 67→            searchInputWithHeader = SearchInputWithHeader(
 68→                uiHelpers = uiHelpers,
 69→                rootView = it.root as ViewGroup,
 70→                onClear = viewModel::onClearTextBtnClicked,
 71→            )
 72→            it.createSiteButton.setOnClickListener { viewModel.onCreateSiteBtnClicked() }
 73→            it.initRecyclerView()
 74→            it.initViewModel()
 75→            it.siteExampleComposeView.setContent {
 76→                AppTheme {
 77→                    SiteExample()
 78→                }
 79→            }
 80→        }
 81→    }
 82→
 83→    private fun SiteCreationDomainsScreenBinding.initRecyclerView() {
 84→        recyclerView.layoutManager = LinearLayoutManager(activity, RecyclerView.VERTICAL, false)
 85→        recyclerView.adapter = SiteCreationDomainsAdapter(uiHelpers)
 86→    }
 87→
 88→    private fun SiteCreationDomainsScreenBinding.initViewModel() {
 89→        viewModel.uiState.observe(viewLifecycleOwner) { uiState ->
 90→            uiState?.let {
 91→                searchInputWithHeader?.updateHeader(requireActivity(), uiState.headerUiState)
 92→                searchInputWithHeader?.updateSearchInput(requireActivity(), uiState.searchInputUiState)
 93→                updateContentUiState(uiState.contentState)
 94→                createSiteButtonContainer.isVisible = uiState.createSiteButtonState != null
 95→                createSiteButton.text = uiState.createSiteButtonState?.stringRes?.let(::getString)
 96→                updateTitleVisibility(uiState.headerUiState == null)
 97→            }
 98→        }
 99→        viewModel.clearBtnClicked.observe(viewLifecycleOwner) { searchInputWithHeader?.setInputText("") }
100→        viewModel.createSiteBtnClicked.observe(viewLifecycleOwner) { domain ->
101→            domain?.let { (requireActivity() as DomainsScreenListener).onDomainSelected(it) }
102→        }
103→        viewModel.onHelpClicked.observe(viewLifecycleOwner) {
104→            (requireActivity() as OnHelpClickedListener).onHelpClicked(HelpActivity.Origin.SITE_CREATION_DOMAINS)
105→        }
106→        viewModel.start()
107→    }
108→
109→    private fun SiteCreationDomainsScreenBinding.updateContentUiState(contentState: DomainsUiContentState) {
110→        uiHelpers.updateVisibility(domainListEmptyView, contentState.emptyViewVisibility)
111→        if (contentState is DomainsUiContentState.Empty && contentState.message != null) {
112→            domainListEmptyViewMessage.text = uiHelpers.getTextOfUiString(requireContext(), contentState.message)
113→        }
114→        uiHelpers.updateVisibility(siteCreationDomainsScreenExample.root, contentState.exampleViewVisibility)
115→        uiHelpers.updateVisibility(siteExampleComposeView, contentState.updatedExampleViewVisibility)
116→        (recyclerView.adapter as SiteCreationDomainsAdapter).update(contentState.items)
117→
118→        if (contentState.items.isNotEmpty()) {
119→            view?.announceForAccessibility(getString(R.string.suggestions_updated_content_description))
120→        }
121→    }
122→
123→    private fun updateTitleVisibility(visible: Boolean) {
124→        val actionBar = (requireActivity() as? AppCompatActivity)?.supportActionBar
125→        actionBar?.setDisplayShowTitleEnabled(displayUtils.isLandscapeBySize() || visible)
126→    }
127→
128→    override fun onHelp() = viewModel.onHelpClicked()
129→
130→    override fun onViewStateRestored(savedInstanceState: Bundle?) {
131→        super.onViewStateRestored(savedInstanceState)
132→        // we need to set the `onTextChanged` after the viewState has been restored otherwise the viewModel.updateQuery
133→        // is called when the system sets the restored value to the EditText which results in an unnecessary request
134→        searchInputWithHeader?.onTextChanged = { viewModel.onQueryChanged(it) }
135→    }
136→
137→    override fun onDestroyView() {
138→        super.onDestroyView()
139→        searchInputWithHeader = null
140→        binding = null
141→    }
142→
143→    private class SearchInputWithHeader(private val uiHelpers: UiHelpers, rootView: View, onClear: () -> Unit) {
144→        private val headerLayout = rootView.findViewById<ViewGroup>(R.id.site_creation_header_item)
145→        private val headerTitle = rootView.findViewById<TextView>(R.id.title)
146→        private val headerSubtitle = rootView.findViewById<TextView>(R.id.subtitle)
147→        private val searchInput = rootView.findViewById<EditText>(R.id.input)
148→        private val progressBar = rootView.findViewById<View>(R.id.progress_bar)
149→        private val clearAllLayout = rootView.findViewById<View>(R.id.clear_all_layout)
150→        private val divider = rootView.findViewById<View>(R.id.divider)
151→        private val showKeyboardHandler = Handler(Looper.getMainLooper())
152→
153→        var onTextChanged: ((String) -> Unit)? = null
154→
155→        init {
156→            clearAllLayout.setOnClickListener {
157→                onClear()
158→            }
159→
160→            searchInput.addTextChangedListener(object : TextWatcher {
161→                override fun afterTextChanged(s: Editable?) = Unit
162→                override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) = Unit
163→                override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
164→                    onTextChanged?.invoke(s?.toString() ?: "")
165→                }
166→            })
167→        }
168→
169→        fun setInputText(text: String) {
170→            // If the text hasn't changed avoid triggering the text watcher
171→            if (searchInput.text.toString() != text) {
172→                searchInput.setText(text)
173→            }
174→        }
175→
176→        fun updateHeader(context: Context, uiState: SiteCreationHeaderUiState?) {
177→            val headerShouldBeVisible = uiState != null
178→            if (!headerShouldBeVisible && headerLayout.isVisible) {
179→                headerLayout.animate().translationY(-headerLayout.height.toFloat())
180→            } else if (headerShouldBeVisible && headerLayout.isGone) {
181→                headerLayout.animate().translationY(0f)
182→            }
183→            uiState?.let {
184→                uiHelpers.updateVisibility(headerLayout, true)
185→                headerTitle.text = uiHelpers.getTextOfUiString(context, uiState.title)
186→                headerSubtitle.text = uiHelpers.getTextOfUiString(context, uiState.subtitle)
187→            } ?: uiHelpers.updateVisibility(headerLayout, false)
188→        }
189→
190→        fun updateSearchInput(context: Context, uiState: SiteCreationSearchInputUiState) {
191→            searchInput.hint = uiHelpers.getTextOfUiString(context, uiState.hint)
192→            uiHelpers.updateVisibility(progressBar, uiState.showProgress)
193→            uiHelpers.updateVisibility(clearAllLayout, uiState.showClearButton)
194→            uiHelpers.updateVisibility(divider, uiState.showDivider)
195→            showKeyboard(uiState.showKeyboard)
196→        }
197→
198→        private fun showKeyboard(shouldShow: Boolean) {
199→            if (shouldShow) {
200→                searchInput.requestFocus()
201→                /**
202→                 * This workaround handles the case where the SiteCreationDomainsFragment appears after the
203→                 * DesignPreviewFragment dismisses and the keyboard fails to appear
204→                 */
205→                showKeyboardHandler.postDelayed({ ActivityUtils.showKeyboard(searchInput) }, SHOW_KEYBOARD_DELAY)
206→            }
207→        }
208→    }
209→
210→    companion object {
211→        const val TAG = "site_creation_domains_fragment_tag"
212→        const val SHOW_KEYBOARD_DELAY = 200L
213→
214→        fun newInstance(screenTitle: String): SiteCreationDomainsFragment {
215→            val fragment = SiteCreationDomainsFragment()
216→            val bundle = Bundle()
217→            bundle.putString(EXTRA_SCREEN_TITLE, screenTitle)
218→            fragment.arguments = bundle
219→            return fragment
220→        }
221→    }
222→}
